int main() {
    int T; scanf("%d", &T);
    while (T--) {
        long long L, R; scanf("%lld %lld", &L, &R);
        long long ans = 0;
        for (long long i = L; i <= R; i++) {
            ans = (ans + i) % (1e9 + 7);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

