code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long L = sc.nextLong();
            long R = sc.nextLong();
            long ans = 0;
            for (long i = L; i <= R; i++) {
                ans = (ans + i) % (1e9 + 7);
            }
            System.out.println(ans);
        }
    }
}

